1в†’import React, { useState, useEffect } from 'react';
2в†’import { Activity, FileText, Wrench, Shield, Users, Calendar, LogOut, UserPlus, Clock, Package } from 'lucide-react';
3в†’
4в†’const API = `${window.location.protocol}//${window.location.host}`;
5в†’
6в†’const Sidebar = ({ user, activeTab, onTabChange, onLogout }) => {
7в†’  const [restingToday, setRestingToday] = useState([]);
8в†’  const [currentTime, setCurrentTime] = useState(new Date());
9в†’
10в†’  useEffect(() => {
11в†’    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
12в†’    return () => clearInterval(timer);
13в†’  }, []);
14в†’
15в†’  useEffect(() => {
16в†’    const fetchResting = async () => {
17в†’      try {
18в†’        const token = localStorage.getItem('token');
19в†’        const res = await fetch(`${API}/rest-days/today`, {
20в†’          headers: { Authorization: `Bearer ${token}` }
21в†’        });
22в†’        if (res.ok) {
23в†’          const data = await res.json();
24в†’          setRestingToday(data);
25в†’        }
26в†’      } catch (e) {}
27в†’    };
28в†’    fetchResting();
29в†’
30в†’    const h = () => fetchResting();
31в†’    window.addEventListener('app-refresh', h);
32в†’
33в†’  }, []);
34в†’
35в†’  const tabs = [
36в†’    { id: 'dashboard', label: 'Monitoring', icon: Activity, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'OPERATOR'] },
37в†’    { id: 'master', label: 'Master Panel', icon: Wrench, roles: ['ADMIN', 'MASTER'] },
38в†’    { id: 'nazoratchi', label: 'Nazoratchi', icon: Shield, roles: ['ADMIN', 'NAZORATCHI'] },
39в†’    { id: 'users', label: 'Foydalanuvchilar', icon: Users, roles: ['ADMIN', 'NAZORATCHI'] },
40в†’    { id: 'reports', label: 'Hisobotlar', icon: FileText, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
41в†’    { id: 'mechanic', label: 'Mexanik', icon: Package, roles: ['ADMIN', 'MASTER', 'OPERATOR'] },
42в†’    { id: 'attendance', label: 'Davomat', icon: Calendar, roles: ['ADMIN', 'MASTER'] },
43в†’    { id: 'schedule', label: 'Jadval', icon: Clock, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
44в†’  ];
45в†’
46в†’  const filteredTabs = tabs.filter(t => t.roles.includes(user.role));
47в†’
48в†’  return (
49в†’    <div className="sidebar">
50в†’      <div className="sidebar-header">
51в†’        <h2>FazoLuxe</h2>
52в†’        <p className="sidebar-user">{user.full_name} ({user.role})</p>
53в†’      </div>
54в†’      <nav className="sidebar-nav">
55в†’        {filteredTabs.map(tab => (
56в†’          <button
57в†’            key={tab.id}
58в†’            className={`sidebar-tab ${activeTab === tab.id ? 'active' : ''}`}
59в†’            onClick={() => onTabChange(tab.id)}
60в†’          >
61в†’            <tab.icon size={18} />
62в†’            <span>{tab.label}</span>
63в†’          </button>
64в†’        ))}
65в†’      </nav>
66в†’      {restingToday.length > 0 && (
67в†’        <div className="sidebar-rest">
68в†’          <p className="rest-title">Bugun dam olish:</p>
69в†’          {restingToday.map(r => (
70в†’            <span key={r.operator_id} className="rest-name">{r.operator_name}</span>
71в†’          ))}
72в†’        </div>
73в†’      )}
74в†’      <div className="sidebar-footer">
75в†’        <div className="sidebar-time">
76в†’          {currentTime.toLocaleTimeString('uz-UZ')}
77в†’        </div>
78в†’        <button className="sidebar-logout" onClick={onLogout}>
79в†’          <LogOut size={16} />
80в†’          <span>Chiqish</span>
81в†’        </button>
82в†’      </div>
83в†’    </div>
84в†’  );
85в†’};
86в†’
87в†’export default Sidebar;
EOF

